import{_ as r,o as a,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Personalization Overview","description":"","frontmatter":{"title":"Personalization Overview","slug":"personalization"},"headers":[],"relativePath":"marketer-hub/personalization.md","filePath":"marketer-hub/personalization.md"}'),i={name:"marketer-hub/personalization.md"};function n(s,e,l,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Using Branch&#39;s Email offering allows you to automatically convert your email links into multi-platform deep links that take users directly to content in-app content on mobile devices, while still maintaining the same web experience for desktop users as well as mobile users without the app.</p><p>In conjunction with this, you can use third party - like <a href="https://movableink.com/" target="_blank" rel="noreferrer">MovableInk</a> and <a href="https://www.liveclicker.com/" target="_blank" rel="noreferrer">Liveclicker</a> - services to create personalized visual experiences that are based on relevant data and are unique for each and every one of your customers.</p><h2 id="required-redirect-parameter" tabindex="-1">Required Redirect Parameter <a class="header-anchor" href="#required-redirect-parameter" aria-label="Permalink to &quot;Required Redirect Parameter&quot;">​</a></h2><p>As these highly-personalized experiences require an additional redirect through the third party service, Branch requires an additional parameter appended to the URL you use in your Branch Email template. This parameter ensures Branch deep links your users to the personalized content you&#39;ve created through the third party service.</p><p>For any Branch Email link that originates from a third party service such as MovableInk and Liveclicker, you must append the following parameter:</p><p><code>$follow_redirect=true</code></p><div class="warning custom-block"><p class="custom-block-title">URL Encoding</p><p>Please URL encode all <code>$</code> symbols before appending the redirect parameter. URL encoding <code>$</code> returns <code>%24</code>.</p></div><p><strong>Example URL + Redirect Parameter</strong></p><p><code>https://cbsn.ws/2KW0dnE?%24follow_redirect=true</code></p><div class="info custom-block"><p class="custom-block-title">Things to Keep in Mind</p><p>Follow the normal ESP configurations in the <code>&lt;a&gt;</code> tags; e.g. if your ESP requires <code>%24deep_link=true</code> as a query param to “branchify”, add it in addition to <code>%24follow_redirect</code>.</p></div><p>Deep link flagging is still required with your ESP. Check out the &quot;Flag your deep links&quot; section for your Branch Email ESP.</p>',12)])])}const m=r(i,[["render",n]]);export{h as __pageData,m as default};
